#!/usr/bin/env -S npx ts-node -r tsconfig-paths/register
/**
 * Example: Configuration File - DEFAULT Profile
 *
 * Description: Use the Databricks CLI configuration file for credentials.
 * This is convenient for local development.
 *
 * Prerequisites:
 * - ~/.databrickscfg file exists
 *
 * Setup:
 * Create ~/.databrickscfg:
 * ```ini
 * [DEFAULT]
 * host = https://your-workspace.cloud.databricks.com
 * token = dapi...
 * ```
 *
 * Run:
 * ```bash
 * npx ts-node examples/auth/config-file-default.ts
 * ```
 */

import {WorkspaceClient} from "@databricks/sdk-experimental";

async function main() {
    // SDK automatically reads ~/.databrickscfg [DEFAULT] profile
    const client = new WorkspaceClient({});

    try {
        const user = await client.currentUser.me();
        console.log(`✓ Successfully authenticated as: ${user.userName}`);
        console.log(`  User ID: ${user.id}`);

        console.log(`  Using config file: ~/.databrickscfg [DEFAULT]`);
        console.log(`  Host: ${client.config.host}`);
    } catch (error) {
        console.error("✗ Authentication failed:", error);
        console.error(
            "\nMake sure ~/.databrickscfg exists with a [DEFAULT] profile:"
        );
        console.error("  [DEFAULT]");
        console.error("  host = https://your-workspace.cloud.databricks.com");
        console.error("  token = dapi...");
        process.exit(1);
    }
}

main().catch(console.error);
